import React from 'react';
import { Navbar as BNavbar, Nav, Container, Badge } from 'react-bootstrap';
import { useAuth } from '../context/AuthContext';

function NavigationBar({ cartCount = 0 }) {
  const { user, logout } = useAuth();

  return (
    <BNavbar bg="dark" variant="dark" expand="lg">
      <Container>
        <BNavbar.Brand href="/">🚗 AutoParts Shop</BNavbar.Brand>
        
        <BNavbar.Toggle aria-controls="basic-navbar-nav" />
        
        <BNavbar.Collapse id="basic-navbar-nav">
          <Nav className="me-auto">
            <Nav.Link href="/search">🔍 Поиск запчастей</Nav.Link>
            <Nav.Link href="/cart">
              🛒 Корзина
              {cartCount > 0 && (
                <Badge bg="danger" pill className="ms-1">{cartCount}</Badge>
              )}
            </Nav.Link>
            <Nav.Link href="/customers">👥 Клиенты</Nav.Link>
            <Nav.Link href="/orders">📋 Заказы</Nav.Link>
          </Nav>
          
          <Nav>
            <Nav.Item className="text-light d-flex align-items-center me-3">
              <small>{user?.fullName} ({user?.role})</small>
            </Nav.Item>
            <Nav.Link onClick={logout} className="text-danger">🚪 Выйти</Nav.Link>
          </Nav>
        </BNavbar.Collapse>
      </Container>
    </BNavbar>
  );
}

export default NavigationBar;
